1	import { App, Button, Card, Flex, Form, Input, Tag, Typography } from 'antd';
2	import { useEffect, useState } from 'react';
3	import { useNavigate, useParams } from 'react-router-dom';
4	
5	import { createCheck, getSuite } from '../api/suites';
6	import { buildCheckPayload } from '../components/checks/checkForm';
7	import { ConfigFieldItem, SeverityThresholdFields } from '../components/checks/checkFormFields';
8	import { DryRunPreview } from '../components/checks/DryRunPreview';
9	import {
10	  EXPECTATION_BY_TYPE,
11	  EXPECTATIONS_BY_CATEGORY,
12	  type ExpectationCategory,
13	} from '../components/checks/expectationCatalog';
14	import { useAsyncData } from '../hooks/useAsyncData';
15	
16	// Monitor-kind categories reserved by ADR 0012 — surfaced (disabled) so the
17	// roadmap is visible; v1 authors GX expectations only.
18	const RESERVED_CATEGORIES = ['Freshness', 'Volume', 'Schema drift'] as const;
19	
20	/**
21	 * Dedicated full-page check authoring flow (GX-Cloud style): pick a category →
22	 * pick an expectation → fill its config + thresholds. Editing an existing check
23	 * still uses the lighter drawer on the suite detail panel.
24	 */
25	export function CheckNew() {
26	  const navigate = useNavigate();
27	  const { suiteId } = useParams<{ suiteId: string }>();
28	  const { message } = App.useApp();
29	  const [category, setCategory] = useState<ExpectationCategory>();
30	  const [expectationType, setExpectationType] = useState<string>();
31	  const [form] = Form.useForm();
32	  const [submitting, setSubmitting] = useState(false);
33	  // The suite's run target (#215) drives the dry-run preview's table/schema.
34	  const { state: suiteState } = useAsyncData(() =>
35	    suiteId ? getSuite(suiteId) : Promise.reject(new Error('no suite')),
36	  );
37	  const target = suiteState.status === 'ok' ? suiteState.data.target : null;
38	
39	  const backToSuite = () => navigate(suiteId ? `/suites/${suiteId}` : '/suites');
40	  const spec = expectationType ? EXPECTATION_BY_TYPE[expectationType] : undefined;
41	
42	  // Start the config form clean each time an expectation is (re)picked — after
43	  // the <Form> mounts (it only renders in the config step), so the store is
44	  // connected and a re-pick can't leak the prior expectation's fields.
45	  useEffect(() => {
46	    if (expectationType) form.resetFields();
47	  }, [expectationType, form]);
48	
49	  const onFinish = async (values: Record<string, unknown>) => {
50	    if (!suiteId || !expectationType) return;
51	    setSubmitting(true);
52	    try {
53	      await createCheck(
54	        suiteId,
55	        buildCheckPayload({ ...values, expectation_type: expectationType }),
56	      );
57	      message.success(`${values.name as string}: created`);
58	      backToSuite();
59	    } catch (err) {
60	      message.error(`Create failed: ${err instanceof Error ? err.message : 'unknown error'}`);
61	    } finally {
62	      setSubmitting(false);
63	    }
64	  };
65	
66	  // Step 3 — config + thresholds for the chosen expectation.
67	  if (spec) {
68	    return (
69	      <Flex vertical gap={24} style={{ maxWidth: 640 }}>
70	        <Header
71	          title={spec.label}
72	          onBack={() => setExpectationType(undefined)}
73	          backLabel="Back to expectations"
74	        />
75	        <Form form={form} layout="vertical" onFinish={onFinish}>
76	          <Typography.Paragraph type="secondary" style={{ marginTop: -8 }}>
77	            {spec.description}
78	          </Typography.Paragraph>
79	          <Form.Item name="name" label="Name" rules={[{ required: true }]}>
80	            <Input placeholder="e.g. order_id not null" />
81	          </Form.Item>
82	          {spec.fields.map((field) => (
83	            <ConfigFieldItem key={field.name} field={field} />
84	          ))}
85	          <SeverityThresholdFields />
86	          {suiteId && (
87	            <Form.Item>
88	              <DryRunPreview
89	                suiteId={suiteId}
90	                expectationType={expectationType}
91	                target={target}
92	                form={form}
93	              />
94	            </Form.Item>
95	          )}
96	          <Flex justify="end" gap={8}>
97	            <Button onClick={() => setExpectationType(undefined)}>Back</Button>
98	            <Button type="primary" htmlType="submit" loading={submitting}>
99	              Create check
100	            </Button>
101	          </Flex>
102	        </Form>
103	      </Flex>
104	    );
105	  }
106	
107	  // Step 2 — pick an expectation within the chosen category.
108	  if (category) {
109	    const group = EXPECTATIONS_BY_CATEGORY.find((g) => g.category === category);
110	    return (
111	      <Flex vertical gap={24} style={{ maxWidth: 720 }}>
112	        <Header
113	          title={category}
114	          onBack={() => setCategory(undefined)}
115	          backLabel="Back to categories"
116	        />
117	        <Flex wrap gap={12}>
