+export interface ColumnProfileRequest {
+  columns: string[];
+  top_n?: number;
+  table?: string | null;
+  schema?: string | null;
+  catalog?: string | null;
+  path?: string | null;
+  file_format?: 'csv' | 'parquet' | null;
