+ */
+export interface CheckDocument {
+  name: string;
+  kind: string;
+  expectation_type: string;
+  config: Record<string, unknown>;
+  warn_threshold: number | string | null;
+  fail_threshold: number | string | null;
+  critical_threshold: number | string | null;
+}
