+export function toFilenameStem(label: string, fallback = 'suite'): string {
+  const stem = label
+    .trim()
+    .toLowerCase()
+    .replace(/[^a-z0-9]+/g, '_')
+    .replace(/^_+|_+$/g, '');
+  return stem || fallback;
+}
